import { httpBatchLink, type HTTPBatchLinkOptions } from '@trpc/client';
import { createTRPCNext, type WithTRPCConfig } from '@trpc/next';
import type { AppRouter } from '../server/routers';
import superjson from 'superjson';

function getBaseUrl() {
  if (typeof window !== 'undefined')
    return '';
  return `http://localhost:${process.env.PORT ?? 3000}`;
}

export const trpc = createTRPCNext<AppRouter>({
  config(opts) {
    const transformer = superjson;

    return {
      links: [
        httpBatchLink({
          url: `${getBaseUrl()}/api/trpc`,
          transformer,
        } as HTTPBatchLinkOptions & { transformer: typeof transformer }),
      ],
    } as WithTRPCConfig<AppRouter>;
  },
  ssr: false,
});

import { inferAsyncReturnType } from '@trpc/server';
import * as trpcNext from '@trpc/server/adapters/next';

type TRPCRequestInfo = {
  calls: Array<{
    getRawInput: () => Promise<unknown>;
  }>;
};

export async function createContext(opts: trpcNext.CreateNextContextOptions) {
  const { info } = opts as trpcNext.CreateNextContextOptions & {
    info: TRPCRequestInfo;
  };
  const rawInput = await info.calls[0].getRawInput();

  return {
    req: opts.req,
    res: opts.res,
    rawInput,
  };
}

export type Context = inferAsyncReturnType<typeof createContext>;

import type { AppProps } from 'next/app';
import { trpc } from '../utils/trpc';

function MyApp({ Component, pageProps }: AppProps) {
  return <Component {...pageProps} />;
}

export default trpc.withTRPC(MyApp);

